using System.ComponentModel;
using System.Text.Json;
using Microsoft.Extensions.AI;
using Microsoft.Agents.AI;
using OpenAI;

// --- Configuration -----------------------------------------------------------

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini";

// --- Tool implementations ----------------------------------------------------

var notebook = new Notebook();

var tools = new AITool[]
{
    AIFunctionFactory.Create(
        (
            [Description("The search query to look up on the web")] string query,
            [Description("Maximum number of results to return (1-10)")] int maxResults = 5
        ) =>
        {
            return WebSearch.SearchAsync(query, maxResults);
        },
        name: "web_search",
        description: "Search the web for information on a topic. Returns a list of results with titles, snippets, and URLs."),

    AIFunctionFactory.Create(
        (
            [Description("Title or label for the note")] string title,
            [Description("Content of the note")] string content
        ) =>
        {
            notebook.AddNote(title, content);
            return $"Note saved: \"{title}\" ({content.Length} chars)";
        },
        name: "save_note",
        description: "Save a research note for later reference. Use this to record key findings, facts, and insights discovered during research."),

    AIFunctionFactory.Create(
        () =>
        {
            var notes = notebook.GetNotes();
            return notes.Count == 0
                ? "No notes saved yet."
                : string.Join("\n\n", notes.Select((n, i) =>
                    $"[{i + 1}] {n.Title}\n{n.Content}"));
        },
        name: "read_notes",
        description: "Read all previously saved research notes."),
};

// --- Agent setup -------------------------------------------------------------

IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

var agent = chatClient.AsAIAgent(
    instructions: """
        You are a thorough research agent. When given a topic:

        1. Search the web multiple times with varied queries to gather broad information.
        2. Save important findings as notes using the save_note tool — include key facts,
           statistics, quotes, and source URLs.
        3. After gathering enough information (at least 3-5 searches), read your notes
           and produce a well-structured summary with:
           - An overview of the topic
           - Key findings organized by theme
           - Notable facts or statistics
           - Sources consulted

        Be methodical: search, save notes, then synthesize. Do not fabricate information
        beyond what the search results provide.
        """,
    name: "ResearchAgent",
    description: "Researches topics by searching the web and taking notes",
    tools: tools);

// --- Main loop ---------------------------------------------------------------

Console.WriteLine("╔══════════════════════════════════════════╗");
Console.WriteLine("║        AI Research Agent                 ║");
Console.WriteLine("║  Type a topic to research, or 'quit'.   ║");
Console.WriteLine("╚══════════════════════════════════════════╝");
Console.WriteLine();

AgentSession? session = null;

while (true)
{
    Console.ForegroundColor = ConsoleColor.Cyan;
    Console.Write("Research topic> ");
    Console.ResetColor();

    var input = Console.ReadLine()?.Trim();
    if (string.IsNullOrEmpty(input)) continue;
    if (input.Equals("quit", StringComparison.OrdinalIgnoreCase)) break;

    notebook.Clear();

    session = await agent.CreateSessionAsync(
        Guid.NewGuid().ToString(), CancellationToken.None);

    Console.ForegroundColor = ConsoleColor.DarkGray;
    Console.WriteLine($"\nResearching \"{input}\"...\n");
    Console.ResetColor();

    try
    {
        var response = await agent.RunAsync(
            $"Research the following topic and provide a comprehensive summary: {input}",
            session,
            new ChatClientAgentRunOptions(new ChatOptions
            {
                Temperature = 0.2f,
                MaxOutputTokens = 4096,
            }),
            CancellationToken.None);

        Console.ForegroundColor = ConsoleColor.Green;
        Console.WriteLine("═══ Research Summary ═══\n");
        Console.ResetColor();
        Console.WriteLine(response.Text);
        Console.WriteLine();

        if (notebook.GetNotes().Count > 0)
        {
            Console.ForegroundColor = ConsoleColor.DarkYellow;
            Console.WriteLine($"[{notebook.GetNotes().Count} note(s) collected during research]");
            Console.ResetColor();
        }
    }
    catch (Exception ex)
    {
        Console.ForegroundColor = ConsoleColor.Red;
        Console.WriteLine($"Error: {ex.Message}");
        Console.ResetColor();
    }

    Console.WriteLine();
}

Console.WriteLine("Goodbye!");

// --- Supporting types --------------------------------------------------------

/// <summary>Simulated web search that uses web fetching to return results.</summary>
static class WebSearch
{
    private static readonly HttpClient Http = new()
    {
        Timeout = TimeSpan.FromSeconds(10),
    };

