 /// <summary>Simulated web search that uses web fetching to return results.</summary>
 static class WebSearch
 {
     private static readonly HttpClient Http = new()
     {
         Timeout = TimeSpan.FromSeconds(10),
     };

     public static async Task<string> SearchAsync(string query, int maxResults)
     {
         maxResults = Math.Clamp(maxResults, 1, 10);

         // Use DuckDuckGo Instant Answer API (no key required)
         var encoded = Uri.EscapeDataString(query);
         var url = $"https://api.duckduckgo.com/?q={encoded}&format=json&no_redirect=1&no_html=1";

         try
         {
             var json = await Http.GetStringAsync(url);
             using var doc = JsonDocument.Parse(json);
             var root = doc.RootElement;

             var results = new List<SearchResult>();

             // Abstract (main answer)
             var abstractText = root.GetProperty("Abstract").GetString();
             var abstractUrl = root.GetProperty("AbstractURL").GetString();
             var abstractSource = root.GetProperty("AbstractSource").GetString();
             if (!string.IsNullOrWhiteSpace(abstractText))
             {
                 results.Add(new SearchResult(
                     $"{abstractSource}: {query}", abstractText, abstractUrl ?? ""));
             }

             // Related topics
             if (root.TryGetProperty("RelatedTopics", out var topics) &&
                 topics.ValueKind == JsonValueKind.Array)
             {
                 foreach (var topic in topics.EnumerateArray())
                 {
                     if (results.Count >= maxResults) break;

                     var text = topic.TryGetProperty("Text", out var t) ? t.GetString() : null;
                     var firstUrl = topic.TryGetProperty("FirstURL", out var u) ? u.GetString() : null;

                     if (!string.IsNullOrWhiteSpace(text))
                     {
                         results.Add(new SearchResult(
                             text.Length > 80 ? text[..80] + "..." : text,
                             text,
                             firstUrl ?? ""));
                     }
                 }
             }

             if (results.Count == 0)
             {
                 return $"No results found for \"{query}\". Try a different search query.";
             }

             return string.Join("\n\n", results.Select((r, i) =>
                 $"Result {i + 1}:\n  Title: {r.Title}\n  Snippet: {r.Snippet}\n  URL: {r.Url}"));
         }
         catch (Exception ex)
         {
             return $"Search failed: {ex.Message}. Try a different query.";
         }
     }

     private record SearchResult(string Title, string Snippet, string Url);
 }

